import{_ as i}from"./chunks/FetchSearch.vue_vue_type_script_setup_true_lang.DaazAy6s.js";import{T as n}from"./chunks/ZigenTrain.DpW6WAfw.js";import{Z as r}from"./chunks/ZigenMap.Bb3_mnCU.js";import{S as d,j as s,m as g,g as e,o as l,n as a}from"./chunks/framework.bs_IcUcR.js";import"./chunks/share.mReafxuL.js";import"./chunks/html2canvas-pro.esm.C7wW9koE.js";import"./chunks/advancedSchedule.CyVEQGBC.js";import"./chunks/cascadeStyles.8DEVsCxs.js";/* empty css                                                                          */const o={class:"zigen-font"},f={class:"zigen-font"},v=JSON.parse('{"title":"月灵","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"ime/yueling.md","filePath":"ime/yueling.md"}'),h={name:"ime/yueling.md"},P=Object.assign(h,{setup(y){return(u,t)=>(d(),s("div",null,[t[0]||(t[0]=g('<h1 id="月灵" tabindex="-1">月灵 <a class="header-anchor" href="#月灵" aria-label="Permalink to &quot;月灵&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><a href="https://github.com/PillowMonth/yueling-ime" target="_blank" rel="noreferrer">月灵</a>输入方案是以灵明为基础，专为简体性能优化的方案。结合了 90% <a href="https://shurufa.app/docs/ling.html" target="_blank" rel="noreferrer">灵明</a>和 10% <a href="https://shurufa.app/docs/ming.html" target="_blank" rel="noreferrer">日月</a>的设计：</p><ol><li>参照日月、灵明，使用 25 键方案，声母 z/zh 用 v 代替，ch 声码为 c，sh 声码为 s，零声母用 j 代替，另外声母 q 用 k 代替以降低 q 键压力；</li><li>字根聚类程度接近灵明；</li><li>大根声码与灵明相同，字根韵码类日月映射至 A、E、U、I、O，单元音除 ü -&gt; E，其余不变，记忆压力较原版灵明稍高；</li><li>为简体字频优化，简体字频全码当量及简体动重大幅降低，繁体动重较高；</li><li>单字编码规则同灵明，编码限长四码；</li></ol><p>月灵方案的设计初衷，源于灵明为兼顾简繁通打而牺牲了部分简体性能，同时灵明为降低学习门槛，采用了以韵腹为核心的韵码取码策略，致使当量难以进一步压缩。月灵虽然在简体动态重码率与当量方面有所精进，但在易学难忘性、繁体静态重码数及繁体动态重码率等指标上，仍远逊于灵明。因此，月灵并不推荐给一般用户或需要输入繁体的使用者，仅适合那些仅有简体输入需求、且对性能有极致追求的用户。对自定码感兴趣的普通用户及形码初学者，建议学习宇浩输入法系列中的「日月」与「灵明」方案。</p><p>使用<a href="https://ceping.shurufa.app" target="_blank" rel="noreferrer">宇浩测评</a>测得的性能指标：</p><ul><li>通用规范 8105 字静重： 296 非首选字；</li><li>常用国字 4808 字静重： 101 非首选字；</li><li>知乎简体·频率降序动重： 1.12‱；</li><li>北语简体·频率降序动重： 1.77‱；</li><li>台标繁体·频率降序动重： 32.06‱；</li><li>知乎简体字频全码当量： 1.2453；</li><li>北语简体字频全码当量： 1.2467；</li><li>台标繁体字频全码当量： 1.2909；</li><li>简码效率： 北语字频 50 简码 3.087，100 简码 2.971，所有简码 2.736；</li></ul><h2 id="映射" tabindex="-1">映射 <a class="header-anchor" href="#映射" aria-label="Permalink to &quot;映射&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">A</th><th style="text-align:left;">E</th><th style="text-align:left;">U</th><th style="text-align:left;">I</th><th style="text-align:left;">O</th></tr></thead><tbody><tr><td style="text-align:left;">a</td><td style="text-align:left;">e Ø</td><td style="text-align:left;">u</td><td style="text-align:left;">i</td><td style="text-align:left;">o ü</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">ao</td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;">ai</td></tr><tr><td style="text-align:left;">er</td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;">ei</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">(k)ua üe uo</td><td style="text-align:left;">ua</td><td style="text-align:left;"></td><td style="text-align:left;">uei</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">ie</td><td style="text-align:left;"></td><td style="text-align:left;">ia</td><td style="text-align:left;">iao iou</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;">ou</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">en ian</td><td style="text-align:left;"></td><td style="text-align:left;">an</td><td style="text-align:left;"></td><td style="text-align:left;">in uan uen iuan</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">ong</td><td style="text-align:left;">eng ing</td><td style="text-align:left;"></td><td style="text-align:left;">ang</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">uang</td><td style="text-align:left;"></td><td style="text-align:left;">iang</td><td style="text-align:left;">iong</td></tr></tbody></table><p>特别注意：</p><ul><li>q 声母映射至 k ，z 声母映射至 v ，零声母声码为 j；</li><li>w 、y 声母不变，仅“肀”：yù，声码取零声母声码 j（yu = ü），全码为：gjo；</li><li>当声码为 k 时，韵母 ua 映射至 e，仅“㐄”、“𰀁”：dke；</li><li>“夂”、“攵”、“夊”归并后，声码取：夂[zh]ǐ → v，韵码取：攵p[ū] → u，全码为 mvu；</li></ul><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h2><ul><li>感谢朱宇浩制作的优质拆分和日月、灵明优质方案；</li><li>感谢 <a href="https://github.com/hertz-hwang" target="_blank" rel="noreferrer">@荒</a> 的<a href="https://github.com/hertz-hwang/code_genie" target="_blank" rel="noreferrer">码灵</a>优化程序；</li><li>感谢上述两位作者的讨论和指导，以及群友及魔灵制作者 <a href="https://github.com/Dieken" target="_blank" rel="noreferrer">@qq3qq</a> 的多次指导与启发；</li></ul><h2 id="拆分" tabindex="-1">拆分 <a class="header-anchor" href="#拆分" aria-label="Permalink to &quot;拆分&quot;">​</a></h2>',14)),e("div",o,[l(i,{chaifenUrl:"/chaifen.json",zigenUrl:"/zigen-yueling.csv",rule:"ling"})]),t[1]||(t[1]=e("h2",{id:"字根",tabindex:"-1"},[a("字根 "),e("a",{class:"header-anchor",href:"#字根","aria-label":'Permalink to "字根"'},"​")],-1)),l(r,{"default-scheme":"yueling",alwaysVisibleZigens:"卩丂丩屮丱髟廾豕彡",chaifenUrl:"/chaifen.json","column-min-width":"1rem",schemeCnName:"月灵",customFooter:"QQ群: 544760766 · 本图链接: https://shurufa.app/ime/yueling"}),t[2]||(t[2]=e("h2",{id:"练习",tabindex:"-1"},[a("练习 "),e("a",{class:"header-anchor",href:"#练习","aria-label":'Permalink to "练习"'},"​")],-1)),e("div",f,[l(n,{name:"yueling",chaifenUrl:"/chaifen.json",zigenUrl:"/zigen-yueling.csv",range:[0],mode:"both",rule:"ling"})])]))}});export{v as __pageData,P as default};
